const prefix = 'wifi2mqtt/pet-feeder/';
const key = msg.topic.replace(prefix, '');
const ts = new Date().toLocaleTimeString('sv-SE');
msg.payload = `[${ts}] ${key.padEnd(14)} ${msg.payload}`;
return msg;

const prefix = 'wifi2mqtt/pet-feeder/';
const key = msg.topic.replace(prefix, '');
let state = flow.get('pf_state') || {};
state[key] = msg.payload;
flow.set('pf_state', state);

const order = ['availability','feeder','mcu','lock','last_error','rssi','ip'];
let lines = ['--- Pet Feeder State ---'];
for (const k of order) {
  if (state[k] !== undefined)
    lines.push(`  ${k.padEnd(14)}: ${state[k]}`);
}
for (const k of Object.keys(state)) {
  if (!order.includes(k))
    lines.push(`  ${k.padEnd(14)}: ${state[k]}`);
}
lines.push('------------------------');
msg.payload = lines.join('\n');
return msg;

const state = flow.get('pf_state') || {};
const order = ['availability','feeder','mcu','lock','last_error','rssi','ip'];
let lines = ['--- Pet Feeder State (on demand) ---'];
for (const k of order) {
  if (state[k] !== undefined)
    lines.push(`  ${k.padEnd(14)}: ${state[k]}`);
}
for (const k of Object.keys(state)) {
  if (!order.includes(k))
    lines.push(`  ${k.padEnd(14)}: ${state[k]}`);
}
if (Object.keys(state).length === 0)
  lines.push('  (no data yet)');
lines.push('------------------------------------');
msg.payload = lines.join('\n');
return msg;

const ts = new Date().toLocaleTimeString('sv-SE');
msg.payload = `[${ts}] LAST ERROR: ${msg.payload}`;
return msg;

const ts = new Date().toLocaleTimeString('sv-SE');
const status = {
  online:     'ONLINE',
  offline:    'OFFLINE',
  restarting: 'RESTARTING (scheduled)'
};
msg.payload = `[${ts}] ${status[msg.payload] || msg.payload}`;
return msg;
